const allItems = $input.all();
const gapList = allItems.map(item => ({
  id: item.json.gap_id,
  question: item.json.question_summary,
  theme: item.json.theme,
  persona: item.json.persona_tag,
  marketing_signal: item.json.marketing_signal
}));

return [{ json: { gaps_json: JSON.stringify(gapList), gaps_count: gapList.length } }];

const allItems = $input.all();

const gapsJson = allItems.length > 0 ? (allItems[0].json.gaps_json || '[]') : '[]';
const gapsCount = allItems.length > 0 ? (allItems[0].json.gaps_count || 0) : 0;
const gapList = JSON.parse(gapsJson);

const ticketList = allItems.map(item => ({
  id: item.json.ticket_id,
  type: item.json.question_type,
  theme: item.json.theme,
  persona: item.json.persona_tag,
  marketing_signal: item.json.marketing_signal,
  summary: item.json.intent_summary,
  answered: item.json.answerable
}));

const weekEnding = new Date().toISOString().split('T')[0];

const combined = {
  week_ending: weekEnding,
  total_tickets: ticketList.length,
  total_gaps: gapsCount,
  answered_tickets: ticketList.filter(t => t.answered).length,
  tickets: ticketList,
  gaps: gapList
};

return [{ json: {
  data: combined,
  week_ending: weekEnding,
  cluster_id: 'WC-' + weekEnding.replace(/-/g, ''),
  total_tickets: ticketList.length,
  total_gaps: gapsCount
} }];

const item = $input.first().json;
const rawText = item.content[0].text;

let clusterData;
try {
  const clean = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  clusterData = JSON.parse(clean);
} catch (e) {
  clusterData = {
    week_summary: 'Parse error — manual review required',
    themes: [],
    top_signals: [],
    new_gaps_count: 0,
    answered_rate_pct: 0
  };
}

return [{ json: {
  cluster_id: item.cluster_id,
  week_ending: item.week_ending,
  themes_json: clusterData.themes || [],
  top_signals: clusterData.top_signals || [],
  week_summary: clusterData.week_summary || '',
  new_gaps_count: item.total_gaps || 0,
  resolved_gaps_count: 0,
  total_tickets: item.total_tickets || 0,
  answered_rate_pct: clusterData.answered_rate_pct || 0
} }];
